document.addEventListener('DOMContentLoaded', () => {
    // 1. Core DOM Elements
    const searchInput = document.getElementById('searchInput');
    const searchButton = document.getElementById('searchButton');
    const searchSuggestions = document.getElementById('searchSuggestions');
    const seeMoreBtn = document.querySelector('.btn-see-more');
    const movieGrid = document.getElementById('movieGrid');

    // Determine current page context
    const isHomepage = !!movieGrid;
    let currentPage = 1;
    const moviesPerPage = 36;
    let activeQuery = '';
    let activeCategory = '';
    let isLoadingNextBatch = false;

    // Category Dropdown Elements
    const categoryFilterContainer = document.getElementById('categoryFilterContainer');
    const categoryDropdownBtn = document.getElementById('categoryDropdownBtn');
    const categoryDropdownMenu = document.getElementById('categoryDropdownMenu');

    // Populate Category Dropdown Dynamically from database
    const populateCategoryDropdown = () => {
        if (!categoryDropdownMenu) return;

        const uniqueCategories = new Set();
        MOVIE_DATABASE.forEach(movie => {
            if (!movie || !movie.category) return;
            const parts = movie.category.split('-').map(s => s.trim());
            parts.forEach(part => {
                if (/^\d{4}$/.test(part)) return; // Skip 4-digit years
                if (part) {
                    uniqueCategories.add(part);
                }
            });
        });

        const sortedCategories = Array.from(uniqueCategories).sort();
        
        categoryDropdownMenu.innerHTML = `
            <div class="category-item active" data-category="">All</div>
        `;

        sortedCategories.forEach(cat => {
            const item = document.createElement('div');
            item.className = 'category-item';
            item.setAttribute('data-category', cat);
            item.textContent = cat;
            categoryDropdownMenu.appendChild(item);
        });

        // Add Event Listeners for category selection
        const categoryItems = categoryDropdownMenu.querySelectorAll('.category-item');
        categoryItems.forEach(item => {
            item.addEventListener('click', () => {
                const selectedCat = item.getAttribute('data-category');
                
                categoryItems.forEach(i => i.classList.remove('active'));
                item.classList.add('active');

                if (categoryDropdownBtn) {
                    categoryDropdownBtn.querySelector('span').textContent = selectedCat ? selectedCat : "All Categories";
                }

                categoryFilterContainer.classList.remove('active');
                applyCategoryFilter(selectedCat);
            });
        });
    };

    // Show/Hide Dropdown
    if (categoryDropdownBtn && categoryFilterContainer) {
        categoryDropdownBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            categoryFilterContainer.classList.toggle('active');
        });

        document.addEventListener('click', (e) => {
            if (!categoryFilterContainer.contains(e.target)) {
                categoryFilterContainer.classList.remove('active');
            }
        });
    }

    const applyCategoryFilter = (cat) => {
        activeCategory = cat;
        if (isHomepage) {
            currentPage = 1;
            renderMovieBatch(1, activeQuery, activeCategory);
        } else {
            window.location.href = `index.html?cat=${encodeURIComponent(cat)}`;
        }
    };

    // Generate movie grid from MOVIE_DATABASE on homepage
    const renderMovieBatch = (page, query = '', category = '') => {
        if (!movieGrid) return;
        
        isLoadingNextBatch = true;
        
        if (page === 1) {
            movieGrid.innerHTML = '';
        }

        const filteredMovies = MOVIE_DATABASE.filter(movie => {
            if (!movie) return false;
            
            const matchesQuery = !query || movie.title.toLowerCase().includes(query.toLowerCase());
            const matchesCategory = !category || movie.category.toLowerCase().includes(category.toLowerCase());
            
            return matchesQuery && matchesCategory;
        });

        // Calculate start and end indices
        const startIndex = (page - 1) * moviesPerPage;
        const endIndex = startIndex + moviesPerPage;
        const batch = filteredMovies.slice(startIndex, endIndex);

        batch.forEach(movie => {
            const card = document.createElement('div');
            card.className = 'movie-card';
            card.style.cursor = 'pointer';
            card.innerHTML = `
                <img src="${movie.image}" alt="${movie.title}" loading="lazy">
                <div class="info">
                    <h3>${movie.title}</h3>
                    <p>${movie.category}</p>
                </div>
            `;
            card.addEventListener('click', () => {
                window.location.href = movie.url;
            });
            movieGrid.appendChild(card);
        });

        // Render placeholders if we are on the last page of all movies and not searching/filtering
        if (!query && !category && endIndex >= filteredMovies.length) {
            for (let i = 0; i < 2; i++) {
                const placeholder = document.createElement('div');
                placeholder.className = 'movie-card coming-soon';
                placeholder.innerHTML = `
                    <div class="cover-placeholder">COMING SOON</div>
                    <div class="info">
                        <h3>Coming Soon</h3>
                        <p>New Release</p>
                    </div>
                `;
                movieGrid.appendChild(placeholder);
            }
        }

        // Show/hide fallback "See more" button
        if (seeMoreBtn) {
            if (endIndex < filteredMovies.length) {
                seeMoreBtn.style.display = 'block';
            } else {
                seeMoreBtn.style.display = 'none';
            }
        }

        // Save total items state for Infinite Scrolling
        if (seeMoreBtn) {
            seeMoreBtn._hasMore = endIndex < filteredMovies.length;
        } else {
            movieGrid._hasMore = endIndex < filteredMovies.length;
        }

        isLoadingNextBatch = false;
    };

    // Filter homepage grid dynamically based on search
    const filterHomepageGrid = (query) => {
        activeQuery = query;
        currentPage = 1;
        renderMovieBatch(1, query, activeCategory);
    };

    // Initial setup for Homepage
    populateCategoryDropdown();

    if (isHomepage) {
        // "See More" Button Fallback Logic
        if (seeMoreBtn) {
            seeMoreBtn.addEventListener('click', () => {
                currentPage++;
                renderMovieBatch(currentPage, activeQuery, activeCategory);
            });
        }

        // Infinite Scroll Integration
        window.addEventListener('scroll', () => {
            if (isLoadingNextBatch) return;
            
            const hasMore = seeMoreBtn ? seeMoreBtn._hasMore : movieGrid._hasMore;
            if (!hasMore) return;

            const triggerOffset = 400; // Load next batch when 400px from the bottom
            if ((window.innerHeight + window.scrollY) >= (document.body.offsetHeight - triggerOffset)) {
                currentPage++;
                renderMovieBatch(currentPage, activeQuery, activeCategory);
            }
        });
    }

    // 2. Search Autocomplete & Filtering Logic
    if (searchInput) {
        searchInput.addEventListener('input', () => {
            const query = searchInput.value.toLowerCase().trim();
            
            if (isHomepage) {
                filterHomepageGrid(query);
            }

            renderSuggestions(query);
        });

        if (searchButton) {
            searchButton.addEventListener('click', () => executeSearch());
        }

        searchInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') {
                executeSearch();
            }
        });
    }

    const renderSuggestions = (query) => {
        if (!searchSuggestions) return;
        searchSuggestions.innerHTML = '';

        if (!query) {
            searchSuggestions.classList.remove('active');
            return;
        }

        const matches = MOVIE_DATABASE.filter(movie => 
            movie && movie.title.toLowerCase().includes(query)
        );

        if (matches.length > 0) {
            matches.slice(0, 10).forEach(movie => {
                const item = document.createElement('div');
                item.className = 'suggestion-item';
                item.innerHTML = `
                    <img src="${movie.image}" alt="${movie.title}">
                    <div class="suggestion-info">
                        <span class="suggestion-title">${movie.title}</span>
                        <span class="suggestion-meta">${movie.category}</span>
                    </div>
                `;
                item.addEventListener('click', () => {
                    window.location.href = movie.url;
                });
                searchSuggestions.appendChild(item);
            });
            searchSuggestions.classList.add('active');
        } else {
            const item = document.createElement('div');
            item.className = 'suggestion-item';
            item.style.cursor = 'default';
            item.innerHTML = `<span style="font-size: 0.85rem; color: #a0a0a0; padding: 0.2rem 0;">No movies found</span>`;
            searchSuggestions.appendChild(item);
            searchSuggestions.classList.add('active');
        }
    };

    document.addEventListener('click', (e) => {
        if (searchSuggestions && !searchInput.contains(e.target) && !searchSuggestions.contains(e.target)) {
            searchSuggestions.classList.remove('active');
        }
    });

    const executeSearch = () => {
        const query = searchInput.value.trim();
        if (!query) return;

        if (isHomepage) {
            filterHomepageGrid(query.toLowerCase());
            searchSuggestions.classList.remove('active');
        } else {
            window.location.href = `index.html?q=${encodeURIComponent(query)}`;
        }
    };

    // 3. Query Parameter Processing (Homepage Auto-Search & Category Filter)
    if (isHomepage) {
        const urlParams = new URLSearchParams(window.location.search);
        
        const urlQuery = urlParams.get('q');
        if (urlQuery) {
            searchInput.value = urlQuery;
            activeQuery = urlQuery;
        }

        const urlCat = urlParams.get('cat');
        if (urlCat) {
            activeCategory = urlCat;
            if (categoryDropdownBtn) {
                categoryDropdownBtn.querySelector('span').textContent = urlCat;
            }
            setTimeout(() => {
                if (categoryDropdownMenu) {
                    const activeItem = categoryDropdownMenu.querySelector(`.category-item[data-category="${urlCat}"]`);
                    if (activeItem) {
                        const categoryItems = categoryDropdownMenu.querySelectorAll('.category-item');
                        categoryItems.forEach(i => i.classList.remove('active'));
                        activeItem.classList.add('active');
                    }
                }
            }, 150);
        }

        renderMovieBatch(1, activeQuery, activeCategory);
    }

    // 5. High-end Adblocker Detection
    const detectAdBlock = () => {
        const bait = document.querySelector('.ad-zone-bait');
        const overlay = document.getElementById('adblockOverlay');
        const body = document.body;
        const mainContent = document.querySelector('.container') || document.querySelector('.player-layout');

        if (!bait || !overlay) return;

        const isBlocked = window.getComputedStyle(bait).getPropertyValue('display') === 'none' || 
                          bait.offsetHeight === 0;

        if (isBlocked) {
            overlay.classList.add('active');
            if (mainContent) mainContent.classList.add('content-blur-premium');
            body.style.overflow = 'hidden';
        }
    };

    setTimeout(detectAdBlock, 600);
    setTimeout(detectAdBlock, 2000);

    const refreshBtn = document.getElementById('refreshBtn');
    if (refreshBtn) {
        refreshBtn.addEventListener('click', () => {
            window.location.reload();
        });
    }
});
